arguments.file_text:
@page "/shipments"
@attribute [Authorize]
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher — Shipments</PageTitle>

<h1>Shipments</h1>

<div class="row mb-3">
    <div class="col-auto">
        <label class="form-label fw-bold">Filter by status:</label>
    </div>
    <div class="col-auto">
        <select class="form-select" @onchange="OnStatusFilterChanged">
            <option value="">All</option>
            @foreach (var status in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@status">@status</option>
            }
        </select>
    </div>
    <div class="col-auto">
        <button class="btn btn-outline-secondary" @onclick="LoadShipments">
            🔄 Refresh
        </button>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments is null || shipments.Count == 0)
{
    <p class="text-muted">No shipments found.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in shipments)
                {
                    <tr>
                        <td><code>@shipment.TrackingNumber</code></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (shipment.Status != ShipmentStatus.Delivered)
                            {
                                <select class="form-select form-select-sm d-inline-block w-auto"
                                        @onchange="e => OnUpdateStatus(shipment.Id, e)">
                                    <option value="">Update…</option>
                                    @foreach (var s in Enum.GetValues<ShipmentStatus>())
                                    {
                                        if (s != shipment.Status)
                                        {
                                            <option value="@s">@s</option>
                                        }
                                    }
                                </select>
                            }
                            else
                            {
                                <span class="text-muted">Delivered @shipment.ActualDelivery?.ToString("MMM dd")</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private ShipmentStatus? currentFilter;
    private bool loading = true;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        shipments = await ShipmentService.GetShipmentsAsync(currentFilter);
        loading = false;
    }

    private async Task OnStatusFilterChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        currentFilter = string.IsNullOrEmpty(value) ? null : Enum.Parse<ShipmentStatus>(value);
        await LoadShipments();
    }

    private async Task OnUpdateStatus(int shipmentId, ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        if (string.IsNullOrEmpty(value)) return;

