    {
        loading = true;
        shipments = await ShipmentService.GetShipmentsAsync(currentFilter);
        loading = false;
    }

    private async Task OnStatusFilterChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        currentFilter = string.IsNullOrEmpty(value) ? null : Enum.Parse<ShipmentStatus>(value);
        await LoadShipments();
    }

    private async Task OnUpdateStatus(int shipmentId, ChangeEventArgs e)
    {
        var value = e.Value?.ToString();
        if (string.IsNullOrEmpty(value)) return;

        var newStatus = Enum.Parse<ShipmentStatus>(value);
        await ShipmentService.UpdateShipmentStatusAsync(shipmentId, newStatus);
        await LoadShipments();
    }

